class Solution {
    public int minPartitions(String n) {
        int result = 0;
        int num = Integer.parseInt(n);
        int power = (int) Math.log10(num) + 1;

        for (int i = power; i >= 1; i--) {
            result += Math.pow(2, i);
        }

        return result;
    }
}
```

